using System.Collections.Generic;
using Il2CppInterop.Runtime.InteropTypes.Arrays;
using Il2CppSystem;
using UnityEngine;

namespace ModMenuCrew.UI;

public static class IconLoader
{
	private static readonly Dictionary<string, Texture2D> _iconCache = new Dictionary<string, Texture2D>(StringComparer.OrdinalIgnoreCase);

	private static bool _initialized = false;

	private const string ICON_BANMENU = "";

	private const string ICON_CHEATS = "";

	private const string ICON_GAME = "";

	private const string ICON_IMPOSTORTAB = "";

	private const string ICON_LOGO = "";

	private const string ICON_LOGO2 = "";

	private const string ICON_MOVIMENTPNG = "";

	private const string ICON_PLAYERPICK = "";

	private const string ICON_SABOTAGE = "";

	private const string ICON_SETTINGS = "";

	private const string ICON_SPOOF = "";

	private static readonly Dictionary<string, string> TabIconMapping = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase)
	{
		{ "Dashboard", "logo2" },
		{ "Lobbies", "logo" },
		{ "Ban Menu", "banmenu" },
		{ "Spoofing", "spoof" },
		{ "Game", "Game" },
		{ "Cheats", "Cheats" },
		{ "Teleport", "movimentpng" },
		{ "Sabotage", "sabotage" },
		{ "Settings", "settings" },
		{ "Movement", "movimentpng" },
		{ "Impostor", "impostortab" },
		{ "Replay", "playerpick" },
		{ "[R] REPLAY", "playerpick" },
		{ "Playerpick", "playerpick" },
		{ "[B] Ban Menu", "banmenu" },
		{ "[S] Spoofing", "spoof" },
		{ "[@] Settings", "settings" },
		{ "[>] DASHBOARD", "logo2" },
		{ "[#] GAME", "Game" },
		{ "[=] MOVEMENT", "movimentpng" },
		{ "[!] SABOTAGE", "sabotage" },
		{ "[X] IMPOSTOR", "impostortab" },
		{ "[*] CHEATS", "Cheats" },
		{ "[P] PlayerPick", "playerpick" }
	};

	public static void Initialize()
	{
		if (!_initialized)
		{
			try
			{
				LoadIcon("banmenu", "");
				LoadIcon("Cheats", "");
				LoadIcon("Game", "");
				LoadIcon("impostortab", "");
				LoadIcon("logo", "");
				LoadIcon("logo2", "");
				LoadIcon("movimentpng", "");
				LoadIcon("playerpick", "");
				LoadIcon("sabotage", "");
				LoadIcon("settings", "");
				LoadIcon("spoof", "");
				Debug.Log(InteropFix.Cast($"[IconLoader] Initialized with {_iconCache.Count} embedded icons."));
			}
			catch (Exception ex)
			{
				Debug.LogError(InteropFix.Cast("[IconLoader] Error: " + ex.Message));
			}
			_initialized = true;
		}
	}

	private static void LoadIcon(string iconName, string base64Data)
	{
		//IL_000b: Unknown result type (might be due to invalid IL or missing references)
		//IL_0011: Expected O, but got Unknown
		try
		{
			byte[] array = Convert.FromBase64String(base64Data);
			Texture2D val = new Texture2D(2, 2, (TextureFormat)4, false);
			((Texture)val).filterMode = (FilterMode)1;
			((Texture)val).wrapMode = (TextureWrapMode)1;
			if (ImageConversion.LoadImage(val, InteropFix.Cast(array), false))
			{
				((Object)val).hideFlags = (HideFlags)61;
				ConvertToTintableWhite(val);
				_iconCache[iconName] = val;
			}
			else
			{
				Debug.LogWarning(InteropFix.Cast("[IconLoader] Failed to load icon: " + iconName));
			}
		}
		catch (Exception ex)
		{
			Debug.LogWarning(InteropFix.Cast("[IconLoader] Error loading " + iconName + ": " + ex.Message));
		}
	}

	private static void ConvertToTintableWhite(Texture2D tex)
	{
		//IL_0030: Unknown result type (might be due to invalid IL or missing references)
		//IL_0035: Unknown result type (might be due to invalid IL or missing references)
		//IL_0036: Unknown result type (might be due to invalid IL or missing references)
		//IL_0040: Unknown result type (might be due to invalid IL or missing references)
		//IL_004d: Unknown result type (might be due to invalid IL or missing references)
		//IL_005b: Unknown result type (might be due to invalid IL or missing references)
		//IL_0087: Unknown result type (might be due to invalid IL or missing references)
		//IL_008d: Unknown result type (might be due to invalid IL or missing references)
		//IL_0092: Unknown result type (might be due to invalid IL or missing references)
		try
		{
			if (!((Texture)tex).isReadable)
			{
				Debug.LogWarning(InteropFix.Cast("[IconLoader] Texture not readable, skipping white conversion"));
				return;
			}
			Color32[] array = InteropFix.Cast((Il2CppArrayBase<Color32>)(object)tex.GetPixels32());
			bool flag = false;
			for (int i = 0; i < array.Length; i++)
			{
				Color32 val = array[i];
				if (val.a > 25 && ((float)(int)val.r * 0.299f + (float)(int)val.g * 0.587f + (float)(int)val.b * 0.114f) / 255f < 0.35f)
				{
					array[i] = new Color32(byte.MaxValue, byte.MaxValue, byte.MaxValue, val.a);
					flag = true;
				}
			}
			if (flag)
			{
				tex.SetPixels32(InteropFix.Cast(array));
			}
			tex.Apply(false, true);
		}
		catch (Exception ex)
		{
			Debug.LogWarning(InteropFix.Cast("[IconLoader] Failed to whiten icon: " + ex.Message));
		}
	}

	public static Texture2D GetIcon(string iconName)
	{
		if (!_initialized)
		{
			Initialize();
		}
		if (_iconCache.TryGetValue(iconName, out var value) && (Object)(object)value != (Object)null)
		{
			return value;
		}
		Debug.LogWarning(InteropFix.Cast("[IconLoader] Icon not found: '" + iconName + "'"));
		return null;
	}

	public static void PreloadAll()
	{
		Initialize();
	}

	public static void ClearCache()
	{
		foreach (Texture2D value in _iconCache.Values)
		{
			if ((Object)(object)value != (Object)null)
			{
				Object.Destroy((Object)(object)value);
			}
		}
		_iconCache.Clear();
		_initialized = false;
	}

	public static Texture2D GetIconForTab(string tabName)
	{
		if (TabIconMapping.TryGetValue(tabName, out var value))
		{
			return GetIcon(value);
		}
		return null;
	}
}


